class VideoStream:
    def __init__(self, video_path, max_buffer_size=10*1024*1024):
        self.video_path = video_path
        self.max_buffer_size = max_buffer_size
        self.buffer = queue.Queue()
        self.stop_flag = False
        self.current_position = 0
        self.lock = threading.Lock()

    def start_streaming(self):
        thread = threading.Thread(target=self._stream_video)
        thread.start()

    def _stream_video(self):
        with open(self.video_path, "rb") as f:
            while not self.stop_flag:
                with self.lock:
                    if self.buffer.qsize() < self.max_buffer_size:
                        data = f.read(1024)
                        if data:
                            self.buffer.put(data)
                        else:
                            self.stop_flag = True
                    else:
                        time.sleep(0.1)

    def read(self, size):
        with self.lock:
            data = b''
            while len(data) < size and not self.stop_flag:
                try:
                    data += self.buffer.get(timeout=1)
                    self.current_position += len(data)
                except queue.Empty:
                    pass
            return data

    def pause(self):
        self.stop_flag = True

    def resume(self):
        self.stop_flag = False
        self.start_streaming()

    def seek(self, position):
        with self.lock:
            self.buffer.queue.clear()
            self.current_position = position
            self.stop_flag = False
            self.start_streaming()

