import os
import sys
import time
import threading
import queue
import requests
import ffmpeg

class VideoStreamingServer:
    def __init__(self, host, port):
        self.host = host
        self.port = port
        self.video_queue = queue.Queue()
        self.user_sessions = {}

    def start(self):
        print(f"Starting video streaming server on {self.host}:{self.port}")
        self.video_processing_thread = threading.Thread(target=self.process_video_queue)
        self.video_processing_thread.start()

    def stop(self):
        print("Stopping video streaming server")
        self.video_processing_thread.join()

    def process_video_queue(self):
        while True:
            video_data = self.video_queue.get()
            self.handle_video_request(video_data)

    def handle_video_request(self, video_data):
        user_id, video_id, action, position = video_data
        if user_id not in self.user_sessions:
            self.user_sessions[user_id] = {}
        user_session = self.user_sessions[user_id]

        if action == "play":
            self.start_video_streaming(user_id, video_id, position)
        elif action == "pause":
            self.pause_video_streaming(user_id, video_id)
        elif action == "seek":
            self.seek_video(user_id, video_id, position)
        elif action == "stop":
            self.stop_video_streaming(user_id, video_id)

    def start_video_streaming(self, user_id, video_id, position):
        if video_id not in user_session or user_session[video_id]["status"] != "playing":
            video_path = self.get_video_path(video_id)
            stream = ffmpeg.input(video_path)
            stream = ffmpeg.output(stream, f"udp://{self.host}:{self.port}/video_{user_id}_{video_id}")
            ffmpeg.run(stream, capture_stdout=True, capture_stderr=True)
            user_session[video_id] = {"status": "playing", "position": position}

    def pause_video_streaming(self, user_id, video_id):
        if video_id in user_session and user_session[video_id]["status"] == "playing":
            user_session[video_id]["status"] = "paused"
            user_session[video_id]["position"] = self.get_current_position(user_id, video_id)

    def seek_video(self, user_id, video_id, position):
        if video_id in user_session and user_session[video_id]["status"] == "playing":
            user_session[video_id]["position"] = position
            self.start_video_streaming(user_id, video_id, position)

    def stop_video_streaming(self, user_id, video_id):
        if video_id in user_session:
            user_session[video_id]["status"] = "stopped"
            user_session[video_id]["position"] = 0

    def get_current_position(self, user_id, video_id):
        if video_id in user_session and user_session[video_id]["status"] == "playing":
            return user_session[video_id]["position"]
        return 0

    def get_video_path(self, video_id):
        return os.path.join("videos", f"{video_id}.mp4")

