    '240p': (426, 240),
    '360p': (640, 360),
    '480p': (854, 480),
    '720p': (1280, 720),
    '1080p': (1920, 1080)
}

# Current viewers
viewers = {}

@app.route('/')
def index():
    return render_template('index.html', resolutions=RESOLUTIONS.keys())

@app.route('/video/<filename>', methods=['GET'])
def video_feed(filename):
    video_path = os.path.join(VIDEO_DIR, filename)
    resolution = request.args.get('resolution', '360p')
    width, height = RESOLUTIONS[resolution]

    def generate_frames():
        probe = ffmpeg.probe(video_path)
        stream_info = next((stream for stream in probe['streams'] if stream['codec_type'] == 'video'), None)
        if not stream_info:
            return

        fps = float(stream_info['avg_frame_rate'])
        duration = float(stream_info['duration'])

        start_time = time.time()
        while True:
            current_time = time.time() - start_time
            if current_time >= duration:
                break

            try:
                (
                    ffmpeg
                    .input(video_path, ss=current_time)
                    .filter('scale', width, height)
                    .output('pipe:', format='mpegts')
                    .run_async(pipe_stdout=True)
                )
                frame = next(iter(ffmpeg.output(ffmpeg.input('pipe:'), 'pipe:', format='mp4').get_stdout_data()))
                yield (b'--frame\r\n'
                       b'Content-Type: image/jpeg\r\n\r\n' + frame + b'\r\n')
                time.sleep(1 / fps)
            except:
                break

    viewer_id = request.remote_addr
    viewers[viewer_id] = time.time()

    return Response(generate_frames(), mimetype='multipart/x-mixed-replace; boundary=frame')

@app.route('/video/<filename>', methods=['POST'])
def control_video(filename):
    viewer_id = request.remote_addr
    action = request.form['action']

    if action == 'pause':
        viewers[viewer_id] = time.time()
    elif action == 'resume':
        viewers[viewer_id] = time.time()
    elif action == 'seek':
        seek_time = float(request.form['seek_time'])
        viewers[viewer_id] = time.time() - seek_time

    return 'OK'

