        with self.lock:
            if video_id not in self.stream_cache:
                self.start_stream(video_id)
            video_data = self.stream_cache[video_id]
            self.update_stream_position(video_id, position)
            return video_data

    def update_stream_position(self, video_id: str, position: float) -> None:
        with self.lock:
            for i, (stream_id, timestamp) in enumerate(self.active_streams):
                if stream_id == video_id:
                    self.active_streams[i] = (stream_id, timestamp + datetime.timedelta(seconds=position))
                    break

    def pause_stream(self, video_id: str) -> None:
        with self.lock:
            for i, (stream_id, timestamp) in enumerate(self.active_streams):
                if stream_id == video_id:
                    self.active_streams[i] = (stream_id, timestamp)
                    break

    def resume_stream(self, video_id: str) -> None:
        with self.lock:
            for i, (stream_id, timestamp) in enumerate(self.active_streams):
                if stream_id == video_id:
                    self.active_streams[i] = (stream_id, datetime.datetime.now())
                    break

    def seek_stream(self, video_id: str, position: float) -> None:
        with self.lock:
            for i, (stream_id, timestamp) in enumerate(self.active_streams):
                if stream_id == video_id:
                    self.active_streams[i] = (stream_id, timestamp + datetime.timedelta(seconds=position))
                    break

    def clean_up_inactive_streams(self) -> None:
        with self.lock:
            now = datetime.datetime.now()
            while self.active_streams and now - self.active_streams[0][1] > datetime.timedelta(minutes=5):
                oldest_stream, _ = self.active_streams.popleft()
                del self.stream_cache[oldest_stream]

    def run_cleanup_task(self) -> None:
