        self.active_streams[stream_id] = {
            "video_id": video_id,
            "user_id": user_id,
            "quality": quality,
            "process": self._start_stream_process(video_id, quality, stream_id)
        }
        self.logger.info(f"Started new stream for user {user_id} with stream_id {stream_id}")
        return stream_id

    def pause_stream(self, stream_id):
        if stream_id in self.active_streams:
            self.active_streams[stream_id]["process"].pause()
            self.logger.info(f"Paused stream with id {stream_id}")

    def resume_stream(self, stream_id):
        if stream_id in self.active_streams:
            self.active_streams[stream_id]["process"].resume()
            self.logger.info(f"Resumed stream with id {stream_id}")

    def seek_stream(self, stream_id, timestamp):
        if stream_id in self.active_streams:
            self.active_streams[stream_id]["process"].seek(timestamp)
            self.logger.info(f"Seeked stream with id {stream_id} to {timestamp}")

    def stop_stream(self, stream_id):
        if stream_id in self.active_streams:
            self.active_streams[stream_id]["process"].terminate()
            del self.active_streams[stream_id]
            self.logger.info(f"Stopped stream with id {stream_id}")
            self._handle_queued_streams()

