# Define video metadata structure
class VideoMetadata:
    def __init__(self, video_id, title, duration, resolutions):
        self.video_id = video_id
        self.title = title
        self.duration = duration
        self.resolutions = resolutions

# Define video stream manager
class VideoStreamManager:
    def __init__(self, video_path):
        self.video_path = video_path
        self.stream_queue = queue.Queue()
        self.stream_threads = []
        self.max_stream_threads = 10

    def start_stream(self, user_id, video_id, resolution, position):
        stream_key = f"{user_id}_{video_id}_{resolution}"
        if stream_key not in self.stream_queue.queue:
            self.stream_queue.put((stream_key, user_id, video_id, resolution, position))
            logging.info(f"New stream started for user {user_id}, video {video_id}, resolution {resolution}, position {position}")
            self._start_stream_thread()

    def _start_stream_thread(self):
        if len(self.stream_threads) < self.max_stream_threads:
            thread = threading.Thread(target=self._stream_video)
            thread.start()
            self.stream_threads.append(thread)

    def _stream_video(self):
        while True:
            try:
                stream_key, user_id, video_id, resolution, position = self.stream_queue.get()
                self._stream_chunk(user_id, video_id, resolution, position)
                self.stream_queue.task_done()
            except queue.Empty:
                break
            except Exception as e:
                logging.error(f"Error streaming video: {e}")

    def _stream_chunk(self, user_id, video_id, resolution, position):
        # Load video file and stream a chunk of data
        with open(self.video_path, 'rb') as f:
            f.seek(position)
            chunk_data = f.read(1024 * 1024)  # 1MB chunk size
            if chunk_data:
                self._send_chunk_to_client(user_id, video_id, resolution, chunk_data, len(chunk_data))
            else:
                logging.info(f"End of video reached for user {user_id}, video {video_id}, resolution {resolution}")

    def _send_chunk_to_client(self, user_id, video_id, resolution, chunk_data, chunk_size):
        # Simulate sending chunk data to client
        time.sleep(0.1)  # Simulate network delay
        logging.info(f"Sent {chunk_size} bytes to user {user_id}, video {video_id}, resolution {resolution}")

