class Video:
    def __init__(self, title, duration, file_size, resolutions):
        self.title = title
        self.duration = duration
        self.file_size = file_size
        self.resolutions = resolutions
        self.current_position = 0

    def play(self, resolution, speed=1.0):
        print(f"Playing {self.title} in {resolution} resolution at {speed}x speed.")
        while self.current_position < self.duration:
            self.current_position += 1 * speed
            time.sleep(1 / speed)
        print(f"Finished playing {self.title}.")

    def pause(self):
        print(f"Paused {self.title} at position {self.current_position}.")

    def seek(self, position):
        self.current_position = position
        print(f"Seeked {self.title} to position {self.current_position}.")

    def get_current_position(self):
        return self.current_position

class StreamingServer:
    def __init__(self):
        self.videos = []
        self.connections = queue.Queue()
        self.max_concurrent_connections = 10

    def add_video(self, video):
        self.videos.append(video)

    def handle_connection(self, connection):
        video = random.choice(self.videos)
        resolution = random.choice(video.resolutions)
        speed = random.uniform(0.5, 2.0)
        print(f"Handling connection for {video.title} in {resolution} resolution at {speed}x speed.")

        try:
            video.play(resolution, speed)
        except Exception as e:
            print(f"Error playing video: {e}")

        self.connections.put(connection)

    def run(self):
        while True:
            if self.connections.qsize() < self.max_concurrent_connections:
                connection = self.connections.get_nowait()
                threading.Thread(target=self.handle_connection, args=(connection,)).start()
            else:
                time.sleep(1)

