class VideoStreamer:
    def __init__(self, video_path):
        self.video_path = video_path
        self.chunk_size = 1024 * 1024  # 1 MB
        self.buffer = deque()
        self.lock = threading.Lock()
        self.last_accessed = time.time()
        self.is_streaming = False

    def start_streaming(self):
        self.is_streaming = True
        threading.Thread(target=self._stream_worker).start()

    def _stream_worker(self):
        with open(self.video_path, 'rb') as f:
            while self.is_streaming:
                with self.lock:
                    chunk = f.read(self.chunk_size)
                    if not chunk:
                        break
                    self.buffer.append(chunk)
                time.sleep(0.1)  # Adjust this value to control the streaming rate

    def get_video_chunk(self) -> Tuple[bytes, bool]:
        with self.lock:
            self.last_accessed = time.time()
            if self.buffer:
                return self.buffer.popleft(), len(self.buffer) > 0
            else:
                return b'', False

    def stop_streaming(self):
        self.is_streaming = False

