        self.video_queues = {video_file: queue.Queue() for video_file in video_files}
        self.video_positions = {video_file: 0 for video_file in video_files}
        self.lock = threading.Lock()

    def start_streaming(self, video_file, user_id):
        queue = self.video_queues[video_file]
        position = self.video_positions[video_file]

