import time
import threading
import queue
import requests
import json

class VideoPlayer:
    def __init__(self, video_url, resolution):
        self.video_url = video_url
        self.resolution = resolution
        self.buffer = queue.Queue()
        self.is_playing = False
        self.current_time = 0
        self.total_duration = 0

    def download_chunk(self):
        while self.is_playing:
            try:
                headers = {'Range': f'bytes={self.current_time}-'}
                response = requests.get(self.video_url, headers=headers, stream=True)
                chunk_size = 1024 * 1024  # 1 MB
                for chunk in response.iter_content(chunk_size=chunk_size):
                    if chunk:
                        self.buffer.put(chunk)
                        self.current_time += len(chunk)
                        if self.current_time >= self.total_duration:
                            break
            except Exception as e:
                print(f"Error downloading chunk: {e}")
                time.sleep(5)

    def play(self):
        self.is_playing = True
        download_thread = threading.Thread(target=self.download_chunk)
        download_thread.start()

        while self.is_playing:
            if not self.buffer.empty():
                chunk = self.buffer.get()
                sys.stdout.buffer.write(chunk)
                sys.stdout.flush()
            else:
                time.sleep(0.1)

        download_thread.join()

    def pause(self):
        self.is_playing = False

    def seek(self, time):
        self.current_time = time
        self.buffer.queue.clear()

    def get_duration(self):
        return self.total_duration

