from urllib.parse import urlparse, parse_qs

class VideoRequestHandler(BaseHTTPRequestHandler):
    def do_GET(self):
        parsed_url = urlparse(self.path)
        query_params = parse_qs(parsed_url.query)

        if parsed_url.path == '/video':
            video_id = query_params.get('id', [None])[0]
            if video_id:
                self.serve_video(video_id)
            else:
                self.send_error(400, 'Missing video ID')
        else:
            self.send_response(404)
            self.end_headers()

    def serve_video(self, video_id):
        video_path = os.path.join('videos', f'{video_id}.mp4')
        if os.path.exists(video_path):
            self.send_response(200)
            self.send_header('Content-Type', 'video/mp4')
            self.end_headers()

            chunk_size = 8192
            with open(video_path, 'rb') as f:
                while True:
                    chunk = f.read(chunk_size)
                    if not chunk:
                        break
                    self.wfile.write(chunk)
        else:
            self.send_error(404, 'Video not found')

class VideoServer:
    def __init__(self, host='localhost', port=8000):
        self.host = host
        self.port = port
        self.server = HTTPServer((self.host, self.port), VideoRequestHandler)

    def start(self):
        print(f'Starting video server at http://{self.host}:{self.port}')
        self.server.serve_forever()

    def stop(self):
