import requests
from flask import Flask, request, send_file, Response
from PIL import Image

app = Flask(__name__)

@app.route('/video/<video_id>', methods=['GET'])
def stream_video(video_id):
    video_path = f'videos/{video_id}.mp4'
    if not os.path.exists(video_path):
        return 'Video not found', 404

    def generate_video():
        CHUNK_SIZE = 1024 * 1024  # 1 MB
        with open(video_path, 'rb') as video_file:
            while True:
                data = video_file.read(CHUNK_SIZE)
                if not data:
                    break
                yield data

    headers = {
        'Content-Type': 'video/mp4',
        'Accept-Ranges': 'bytes'
    }

    range_header = request.headers.get('Range', None)
    if range_header:
        start, end = map(int, (range_header.replace('bytes=', '')).split('-'))
        headers['Content-Range'] = f'bytes {start}-{end}/{os.path.getsize(video_path)}'
        headers['Content-Length'] = str(end - start + 1)
        return Response(generate_video(), status=206, headers=headers)
    else:
        headers['Content-Length'] = str(os.path.getsize(video_path))
        return Response(generate_video(), headers=headers)

@app.route('/thumbnail/<video_id>', methods=['GET'])
def get_thumbnail(video_id):
    thumbnail_path = f'thumbnails/{video_id}.jpg'
    if not os.path.exists(thumbnail_path):
        return 'Thumbnail not found', 404

    return send_file(thumbnail_path, mimetype='image/jpeg')

if __name__ == '__main__':
    app.run(debug=True)

