import threading
import queue

class VideoPlayer:
    def __init__(self):
        self.queue = queue.Queue()
        self.current_video = None
        self.paused = False
        self.seek_time = 0

    def add_video(self, video_path):
        self.queue.put(video_path)

    def play_video(self):
        while True:
            if not self.queue.empty():
                video_path = self.queue.get()
                self.current_video = video_path
                self.play(video_path)
            else:
                time.sleep(1)

    def play(self, video_path):
        if self.paused:
            subprocess.call(["vlc", "--play-and-pause", video_path, f"--start-time={self.seek_time}"])
        else:
            subprocess.call(["vlc", video_path, f"--start-time={self.seek_time}"])

        self.paused = False
        self.seek_time = 0

    def pause(self):
        self.paused = True
        subprocess.call(["vlc", "--pause"])

    def seek(self, time):
        self.seek_time = time
        subprocess.call(["vlc", "--pause"])

    def jump_forward(self):
        self.seek(self.seek_time + 10)
        self.play(self.current_video)

    def jump_backward(self):
        self.seek(self.seek_time - 10)
        self.play(self.current_video)

