import os
import time
import threading
import queue
import requests
from typing import Union, Tuple

class VideoPlayer:
    def __init__(self, video_url: str, buffer_size: int = 1024 * 1024):
        self.video_url = video_url
        self.buffer_size = buffer_size
        self.buffer = queue.Queue()
        self.is_playing = False
        self.current_position = 0
        self.download_thread = None
        self.playback_thread = None

    def download_video(self):
        while self.is_playing:
            try:
                response = requests.get(self.video_url, headers={'Range': f'bytes={self.current_position}-'}, stream=True)
                for chunk in response.iter_content(chunk_size=self.buffer_size):
                    if chunk:
                        self.buffer.put(chunk)
                        self.current_position += len(chunk)
            except (requests.exceptions.RequestException, queue.Full):
                time.sleep(0.1)

    def play_video(self):
        while self.is_playing:
            try:
                chunk = self.buffer.get(timeout=1)
                # Process the video chunk here
                time.sleep(len(chunk) / (self.buffer_size * 30))  # Assuming 30 fps
            except queue.Empty:
                time.sleep(0.1)

    def start(self):
        self.is_playing = True
        self.download_thread = threading.Thread(target=self.download_video)
        self.playback_thread = threading.Thread(target=self.play_video)
        self.download_thread.start()
        self.playback_thread.start()

    def stop(self):
        self.is_playing = False
        self.download_thread.join()
        self.playback_thread.join()

    def seek(self, position: Union[int, float]):
        self.current_position = int(position * 1024 * 1024)

    def pause(self):
        self.is_playing = False

    def resume(self):
        self.is_playing = True

    def jump_forward(self, seconds: float):
        self.seek(self.current_position + seconds * 1024 * 1024)

    def jump_backward(self, seconds: float):
        self.seek(self.current_position - seconds * 1024 * 1024)

