class TVStreamWebApp:
    def __init__(self):
        self.video_library = {}
        self.user_sessions = {}
        self.network_conditions = {}

    def add_video(self, video_id, video_url, video_size, resolution):
        self.video_library[video_id] = {
            'url': video_url,
            'size': video_size,
            'resolution': resolution
        }

    def start_user_session(self, user_id, connection_quality):
        self.user_sessions[user_id] = {
            'position': 0,
            'paused': False
        }
        self.network_conditions[user_id] = connection_quality

    def watch_video(self, user_id, video_id):
        user_session = self.user_sessions[user_id]
        video_info = self.video_library[video_id]
        connection_quality = self.network_conditions[user_id]

        while user_session['position'] < video_info['size']:
            if user_session['paused']:
                time.sleep(1)
                continue

            download_speed = self.simulate_download(connection_quality)
            bytes_downloaded = min(download_speed, video_info['size'] - user_session['position'])
            user_session['position'] += bytes_downloaded

            if user_session['position'] >= video_info['size']:
                print(f"User {user_id} finished watching video {video_id}")
                break

            time.sleep(1)

    def simulate_download(self, connection_quality):
        if connection_quality == 'high':
            return 1024 * 1024  # 1 MB/s
        elif connection_quality == 'medium':
            return 512 * 1024  # 0.5 MB/s
        elif connection_quality == 'low':
            return 256 * 1024  # 0.25 MB/s
        else:
